// Test: Basic try-catch block
public class ExceptionHandler
{
    public int SafeDivide(int a, int b)
    {
        try
        {
            return a / b;
        }
        catch (DivideByZeroException ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
            return 0;
        }
    }
}

// Test: Try-catch-finally block with actual content
public class ExceptionHandler
{
    public int ComplexCalculation(int[] numbers)
    {
        int result = 0;

        try
        {
            result = numbers.Sum() / numbers.Length;
        }
        catch (DivideByZeroException ex)
        {
            Console.WriteLine($"Division error: {ex.Message}");
            result = 0;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"General error: {ex.Message}");
            result = -1;
        }
        finally
        {
            Console.WriteLine("Calculation completed");
            Console.WriteLine($"Final result: {result}");
        }

        return result;
    }
}

// Test: For loop with break and continue
public class LoopProcessor
{
    public List<int> ProcessNumbers(List<int> numbers)
    {
        var result = new List<int>();

        for (int i = 0; i < numbers.Count; i++)
        {
            int current = numbers[i];

            if (current < 0)
            {
                continue;
            }

            if (current > 100)
            {
                break;
            }

            result.Add(current * 2);
        }

        return result;
    }
}

// Test: Foreach loop
public class LoopProcessor
{
    public int SumPositive(int[] numbers)
    {
        int sum = 0;

        foreach (int number in numbers)
        {
            if (number > 0)
            {
                sum += number;
            }
        }

        return sum;
    }
}

// Test: While loop
public class LoopProcessor
{
    public int Factorial(int n)
    {
        if (n <= 1)
        {
            return 1;
        }

        int result = 1;
        while (n > 1)
        {
            result *= n;
            n--;
        }

        return result;
    }
}

