// Test: Modern switch expressions with relational patterns
public class GradeCalculator
{
    public string GetGrade(int score)
    {
        switch (score)
        {
            case >= 90:
                return "A";
            case >= 80:
                return "B";
            case >= 70:
                return "C";
            case >= 60:
                return "D";
            default:
                return "F";
        }
    }
}

// Test: Traditional switch statement
public class GradeCalculator
{
    public string GetLetterGrade(int score)
    {
        switch (score / 10)
        {
            case 10:
            case 9:
                return "A";
            case 8:
                return "B";
            case 7:
                return "C";
            case 6:
                return "D";
            default:
                return "F";
        }
    }
}
